oxy_webhelp_navlinks = {"openstack_vms-d27248e23939":{"topics":[{"title":"Add an OpenStack virtual machine","shortdesc":"<p class=\"shortdesc\">Add an OpenStack virtual machine to <span class=\"ph\">RSC<\/span> so you can perform snapshots         to protect your data.<\/p>","href":"openstack\/add_openstack_virtual_machine.html","attributes":{"data-id":"add_openstack_virtual_machine"},"menu":{"hasChildren":false},"tocID":"add_openstack_virtual_machine-d27248e23952","next":"add_openstack_virtual_machine-d27248e23952"},{"title":" OpenStack virtual machine management","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">RSC<\/span> to onboard, refresh, edit, monitor, and delete         OpenStack virtual machines.<\/p>","href":"openstack\/openstack_vm_management.html","attributes":{"data-id":"openstack_vm_management."},"menu":{"hasChildren":false},"tocID":"openstack_vm_management.-d27248e23994","next":"openstack_vm_management.-d27248e23994"},{"title":"Set up protection for OpenStack virtual machines","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects OpenStack virtual machines and regions using SLA Domains         and on-demand snapshots. <\/p>","href":"openstack\/setup_protection_openstack_vms.html","attributes":{"data-id":"setup_protection_openstack_vms"},"menu":{"hasChildren":false},"tocID":"setup_protection_openstack_vms-d27248e24069","next":"setup_protection_openstack_vms-d27248e24069"},{"title":"Manage protection for OpenStack virtual machines","shortdesc":"<p class=\"shortdesc\">After completing the protection setup for OpenStack virtual machines, <span class=\"ph\">RSC<\/span> takes automated snapshots of those virtual machines and disks based on         the configured policies in SLA Domains. You can also take on-demand snapshots, recover files         and folders from OpenStack virtual machines, and export OpenStack virtual machine         snapshots.<\/p>","href":"openstack\/manage_protection_openstack_vms.html","attributes":{"data-id":"manage_protection_openstack_vms"},"menu":{"hasChildren":false},"tocID":"manage_protection_openstack_vms-d27248e24093","next":"manage_protection_openstack_vms-d27248e24093"},{"title":"Recover OpenStack virtual machines","shortdesc":"<p class=\"shortdesc\">You can recover files and folders used by OpenStack virtual machines by mounting         snapshots from local clusters or remote archival locations. You can also export an OpenStack         virtual machine snapshot to create a point-in-time copy for backup or migration.<\/p>","href":"openstack\/recover_openstack_vms.html","attributes":{"data-id":"recover_openstack_vms"},"menu":{"hasChildren":false},"tocID":"recover_openstack_vms-d27248e24129","next":"recover_openstack_vms-d27248e24129"}]}};